echo "=== Full real-sorry list with enclosing decl (QuotScheme, FlatteningStratification, RelPicFunctor, FGAPic) ==="
for f in FGAPicRepresentability QuotScheme FlatteningStratification RelPicFunctor; do
  p="AlgebraicJacobian/Picard/$f.lean"
  echo ""
  echo "############## $f.lean ##############"
  awk '
    /^[[:space:]]*(theorem|lemma|def|instance|noncomputable def|noncomputable instance|abbrev)[[:space:]]/ { decl=$0; declline=NR }
    /^[[:space:]]*(theorem|lemma|def|instance|abbrev|noncomputable)/ { last=$0 }
    {
      line=$0
      # detect a real sorry: sorry as a token, on a line that is not a -- comment and not obvious prose
      if (line ~ /\bsorry\b/ && line !~ /^[[:space:]]*--/ && line !~ /sorry-|`sorry`|sorries|typed sorry|sorry token|sorry-free|⟨sorry⟩-backed|awaiting|carrier|carrying|placeholder|instance was|conditional on|genuine|unique sorry/) {
        print NR": "line"   [decl@"declline": "substr(decl,1,80)"]"
      }
    }
  ' "$p"
done 2>&1 | head -100
